pythonCopierimport ast
import os
import re
from core.templates.view_loader import load_template_view, detect_file_type_from_template

def extract_meta_block(file_content):
    pattern = r'""".*?"""'
    matches = re.findall(pattern, file_content, re.DOTALL)
    for block in matches:
        if ":" in block:
            return block
    return None

def parse_meta_block(meta_block):
    meta_dict = {}
    lines = meta_block.strip('"""').strip().splitlines()
    for line in lines:
        if line.strip().startswith(":") and ":" in line[1:]:
            key, val = line.strip()[1:].split(":", 1)
            meta_dict[key.strip()] = val.strip()
    return meta_dict

def detect_type_from_ast(file_content):
    try:
        tree = ast.parse(file_content)
        class_count = sum(isinstance(node, ast.ClassDef) for node in ast.walk(tree))
        func_count = sum(isinstance(node, ast.FunctionDef) for node in ast.walk(tree))
        if class_count >= 1:
            return "class"
        elif func_count == 1:
            return "action"
        elif func_count > 1:
            return "function"
        else:
            return "file"
    except Exception:
        return "file"

def get_required_fields_for_type(file_type):
    try:
        from core.ontology.filetype import get_required_fields
        return get_required_fields(file_type.capitalize() + "File")
    except Exception:
        return ["filename", "description", "type"]

def check_file_against_template(file_path):
    with open(file_path, "r", encoding="utf-8") as f:
        content = f.read()

    result = {
        "file": file_path,
        "type": detect_type_from_ast(content),
        "status": "ok",
        "missing": [],
        "found": {}
    }

    meta_block = extract_meta_block(content)
    if not meta_block:
        result["status"] = "missing_meta_block"
        return result

    meta_dict = parse_meta_block(meta_block)
    result["found"] = meta_dict

    required_fields = get_required_fields_for_type(result["type"])
    missing = [field for field in required_fields if field not in meta_dict]
    if missing:
        result["status"] = "missing_fields"
        result["missing"] = missing

    return result

def fix_file_against_template(file_path, file_type, missing_fields, overrides):
    try:
        with open(file_path, "r", encoding="utf-8") as f:
            content = f.read()

        meta_block = extract_meta_block(content)
        new_meta = {}
        if meta_block:
            new_meta = parse_meta_block(meta_block)
        else:
            print("🛠️ Aucun bloc meta détecté, insertion en tête du fichier.")

        for field in missing_fields:
            new_meta[field] = overrides.get(field, f"AUTO_{field}")

        full_block = '"""\n' + "\n".join(f":{k}: {v}" for k, v in new_meta.items()) + '\n"""\n\n'

        if meta_block:
            content = content.replace(meta_block, full_block)
        else:
            content = full_block + content

        with open(file_path, "w", encoding="utf-8") as f:
            f.write(content)

        return True
    except Exception as e:
        print("❌ Erreur lors de la correction :", e)
        return False

def validate_meta_content(metas, file_type):
    issues = []
    if "type" in metas and metas["type"] != file_type:
        issues.append(f":type: doit être '{file_type}' mais vaut '{metas['type']}'")
    if "filename" in metas and not metas["filename"].endswith((".py", ".md")):
        issues.append(f":filename: semble incorrect ({metas['filename']})")
    if "description" in metas and (len(metas["description"]) < 5 or "fichier" in metas["description"].lower()):
        issues.append(":description: est trop courte ou générique")
    return issues

__all__ = [
    "check_file_against_template",
    "fix_file_against_template",
    "get_required_fields_for_type",
    "validate_meta_content"
]


